import{c as i,Q as t,j as o,m as a}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I manage my notification subscriptions?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/account/manage-notifications.md","filePath":"guide/recipes/account/manage-notifications.md","lastUpdated":1778912818000}'),s={name:"guide/recipes/account/manage-notifications.md"};function n(r,e,c,l,d,p){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-manage-my-notification-subscriptions" tabindex="-1">How do I manage my notification subscriptions? <a class="header-anchor" href="#how-do-i-manage-my-notification-subscriptions" aria-label="Permalink to &quot;How do I manage my notification subscriptions?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>Anyone — for <strong>your own</strong> subscriptions</p></div><p>Notifications are grouped by category (Operations, Discrepancies, Billing, Infrastructure, General) and delivered both in-app and via email. You decide which categories you receive.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Account</strong> in the sidebar.</li><li>Scroll to <strong>Notifications</strong>.</li><li>For each category, toggle: <ul><li><strong>In-app</strong> — shows in the notification bell.</li><li><strong>Email</strong> — sends to your registered email address.</li></ul></li><li>Changes save automatically.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>You stop receiving the categories you toggled off. Other recipients of the same notifications aren&#39;t affected — subscriptions are per-user.</p><div class="tip custom-block"><p class="custom-block-title">Required subscriptions</p><p>Some categories are marked <strong>Required</strong> based on your role (for example, Compliance Admins always receive discrepancy alerts). Required subscriptions can&#39;t be turned off.</p></div>',8)])])}const g=i(s,[["render",n]]);export{m as __pageData,g as default};
